  ('social-worker-moex-07540', 'social-worker', 'social-worker-moex-100-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據全民健康保險法第8條之規定，具有中華民國國籍，最近2年內曾有參加本保險紀錄且在臺灣地區 設有戶籍，或參加本保險前幾個月繼續在臺灣地區設有戶籍，始符合投保資格？', '["3個月", "6個月", "9個月", "12個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "e63ebc50cc49", "answer_pdf_sha1": "6abe37460ba6", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07541', 'social-worker', 'social-worker-moex-100-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依就業保險法之規定，失業給付按申請人離職辦理本保險退保之當月起前 6個月平均月投保薪資60%按 月發給，老王離職退保時已50歲，在非經濟不景氣致大量失業或其他緊急情事時，請問最長可發給幾個 月？', '["3個月", "6個月", "9個月", "12個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "e63ebc50cc49", "answer_pdf_sha1": "6abe37460ba6", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07542', 'social-worker', 'social-worker-moex-100-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列對於失業保險特性之敘述，何者錯誤？', '["須為非自願性失業者", "失業保險的給付金額與過去所得無關", "失業保險的資格必須視過去的繳費紀錄而定", "失業給付領取結束後，須一定期間才能再度享有給付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "e63ebc50cc49", "answer_pdf_sha1": "6abe37460ba6", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07543', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：社會工作師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07544', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Maccoby與Jacklin（1974）對兒童性別差異的看法，下列敘述何者不正確？', '["女性的語言能力較男性為強", "男性的視覺與空間較強", "兩性在數學能力上無差異", "男性比較具有侵犯性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07545', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作師工作的重點不僅著重在個人，而且也包括其所屬之家庭、組織或社區環境，此種觀點稱為：', '["任務中心觀點", "精神分析觀點", "生態系統觀點", "充權觀點"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
